fixed_code:
use std::thread;

struct MyStruct {
    data: String,
}

fn main() {
    let s = MyStruct { data: String::from("hello") };
    {
        let t = thread::spawn(move || println!("{}", s.data));
        // Move the clone into the scope instead of the original variable
        let _ = t.join();
    }
}
